using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelTrainer
{
    private readonly ILogger<TicketModelTrainer> _logger;
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public TicketModelTrainer(ILogger<TicketModelTrainer> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public string ModelPath => _modelPath;

    public string[] Labels { get; private set; } = [];

    public void TrainAndEvaluate()
    {
        _logger.LogInformation("Loading training data from {Path}", _dataPath);

        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        // Extract label names from the Score column metadata
        var testPredictions = model.Transform(split.TestSet);
        var scoreColumn = testPredictions.Schema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        Labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
        _logger.LogInformation("Labels: {Labels}", string.Join(", ", Labels));

        // Evaluate on test set
        var metrics = _mlContext.MulticlassClassification.Evaluate(testPredictions, "Label");

        _logger.LogInformation("=== Model Evaluation Metrics (Test Set) ===");
        _logger.LogInformation("  Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("  Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("  Log Loss Reduction:{LogLossReduction:F4}", metrics.LogLossReduction);

        // Also evaluate on the full dataset
        var fullPredictions = model.Transform(data);
        var fullMetrics = _mlContext.MulticlassClassification.Evaluate(fullPredictions, "Label");

        _logger.LogInformation("=== Full Dataset Metrics ===");
        _logger.LogInformation("  Macro Accuracy:    {MacroAccuracy:F4}", fullMetrics.MacroAccuracy);
        _logger.LogInformation("  Micro Accuracy:    {MicroAccuracy:F4}", fullMetrics.MicroAccuracy);
        _logger.LogInformation("  Log Loss:          {LogLoss:F4}", fullMetrics.LogLoss);

        _mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }
}

